import{_ as a,c as t,o as r,ag as n}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"WebUI Handlers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/handlers/index.md","filePath":"guide/concepts/handlers/index.md"}'),o={name:"guide/concepts/handlers/index.md"};function i(l,e,s,d,c,h){return r(),t("div",null,e[0]||(e[0]=[n('<h1 id="webui-handlers" tabindex="-1">WebUI Handlers <a class="header-anchor" href="#webui-handlers" aria-label="Permalink to &quot;WebUI Handlers&quot;">​</a></h1><p>WebUI handlers are the bridge between the WebUI protocol and the final rendered HTML output. They process the protocol and render the content in a specific programming language.</p><h2 id="available-handlers" tabindex="-1">Available Handlers <a class="header-anchor" href="#available-handlers" aria-label="Permalink to &quot;Available Handlers&quot;">​</a></h2><p>WebUI provides official handlers for several popular programming languages (other languages coming soon):</p><ul><li><a href="./rust.html"><strong>Rust</strong></a> - High-performance native rendering with the Rust programming language</li></ul><h2 id="how-handlers-work" tabindex="-1">How Handlers Work <a class="header-anchor" href="#how-handlers-work" aria-label="Permalink to &quot;How Handlers Work&quot;">​</a></h2><p>All WebUI handlers follow the same pattern:</p><ol><li>They accept a WebUI protocol object (usually parsed from JSON)</li><li>They process the protocol with the provided state data</li><li>They render the final HTML output by evaluating directives and inserting dynamic content</li></ol><p>This consistent approach ensures that the same template produces identical results across different programming languages and platforms.</p><h2 id="common-handler-interface" tabindex="-1">Common Handler Interface <a class="header-anchor" href="#common-handler-interface" aria-label="Permalink to &quot;Common Handler Interface&quot;">​</a></h2><p>While the specific implementation details vary between languages, all handlers provide a similar API:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>handle(protocol, state, writer)</span></span></code></pre></div><p>Where:</p><ul><li><code>protocol</code> is the WebUI protocol object</li><li><code>state</code> is the data object with values to be rendered</li><li><code>writer</code> is a callback or interface for writing the rendered output</li></ul><h2 id="handler-customization" tabindex="-1">Handler Customization <a class="header-anchor" href="#handler-customization" aria-label="Permalink to &quot;Handler Customization&quot;">​</a></h2><p>Each handler implementation can be extended or customized to fit specific requirements. See the individual handler documentation for language-specific details.</p>',16)]))}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
